const config = $json;
const stageFilters = config.stageFilters || {};
const staffReviewRules = config.staffReviewRules || {};
const qualificationRules = config.qualificationRules || {};
const selectedStages = Array.isArray(stageFilters.selectedStages) ? stageFilters.selectedStages : [];

const promptSections = [
  `Tone: ${config.tone || 'warm'}`,
  '',
  'Base prompt:',
  config.prompt || '',
  '',
  'Prompt notes from dashboard:',
  qualificationRules.promptNotes || 'No dashboard prompt notes saved.',
  '',
  'Safety rules:',
  ...(config.safetyRules || []).map((rule) => `- ${rule}`),
  '',
  'Staff review rule:',
  staffReviewRules.rule || 'Escalate finance, complaints, medical uncertainty, and same-day appointment requests.',
  '',
  'Allowed Boxly stages:',
  selectedStages.length ? selectedStages.map((item) => `- ${item.box} / ${item.stage}`) : ['- No stage filter configured.'],
];

return [{
  json: {
    practiceId: config.practiceId,
    configVersion: config.versionNumber,
    launchState: config.launchState || 'draft',
    autoContactEnabled: Boolean(config.autoContactEnabled),
    firstMessage: config.firstMessage,
    promptForAiNode: promptSections.join('\n'),
    controlSettings: {
      stageFilters,
      selectedStages,
      priorityLanes: qualificationRules.priorityLanes || [],
      reminder: stageFilters.reminder || null,
      autoTrigger: stageFilters.autoTrigger || null,
      staffReviewRules,
    },
  }
}];

const liveConfigWouldAllowSend = $json.launchState === 'live' && $json.autoContactEnabled === true;

return [{
  json: {
    ...$json,
    liveConfigWouldAllowSend,
    sendAllowed: false,
    reason: liveConfigWouldAllowSend
      ? 'Live config detected, but this draft workflow keeps sends disabled by design.'
      : 'Config is draft, paused, preview, or auto-contact is disabled.',
  }
}];
